function solve(nums: number[], k: number): number {
    let total = 0;
    let mod = 0;
    let minSum = Infinity;

    for (let num of nums) {
        total += num;
        mod = (mod + num) % k;

        // Check if current mod is 0, meaning the subarray from start to current is divisible by k
        if (mod === 0) {
            minSum = Math.min(minSum, total);
        }
    }

    // If no subarray found, return the sum of all elements
    return minSum === Infinity ? total : minSum;
}

